380→    private fun onRecommendedSiteItemClicked(blogId: Long, feedId: Long, isFollowed: Boolean) {
381→        readerTracker.trackBlog(
382→            AnalyticsTracker.Stat.READER_SUGGESTED_SITE_VISITED,
383→            blogId,
384→            feedId
385→        )
386→        _navigationEvents.postValue(Event(ShowBlogPreview(blogId, feedId, isFollowed)))
387→    }
