466→    private fun changeMoreMenuVisibilityNew(currentUiState: ReaderPostNewUiState, show: Boolean) {
467→        launch {
468→            findPost(currentUiState.postId, currentUiState.blogId)?.let { post ->
469→                val moreMenuItems = if (show) {
470→                    readerPostMoreButtonUiStateBuilder.buildMoreMenuItems(
471→                        post, true, this@ReaderDiscoverViewModel::onButtonClicked
472→                    )
473→                } else {
474→                    null
475→                }
476→
477→                replaceUiStateItem(currentUiState, currentUiState.copy(moreMenuItems = moreMenuItems))
478→            }
479→        }
