493→    fun onReblogSiteSelected(siteLocalId: Int) {
494→        launch {
495→            val state = reblogUseCase.onReblogSiteSelected(siteLocalId, pendingReblogPost)
496→            val navigationTarget = reblogUseCase.convertReblogStateToNavigationEvent(state)
497→            if (navigationTarget != null) {
498→                _navigationEvents.value = Event(navigationTarget)
499→            } else {
500→                _snackbarEvents.value = Event(SnackbarMessageHolder(UiStringRes(R.string.reader_reblog_error)))
501→            }
502→            pendingReblogPost = null
503→        }
504→    }
