527→    sealed class DiscoverUiState(
528→        val contentVisiblity: Boolean = false,
529→        val fullscreenProgressVisibility: Boolean = false,
530→        val swipeToRefreshEnabled: Boolean = false,
531→        open val fullscreenEmptyVisibility: Boolean = false,
532→    ) {
533→        open val reloadProgressVisibility: Boolean = false
534→        open val loadMoreProgressVisibility: Boolean = false
535→
536→        data class ContentUiState(
537→            val cards: List<ReaderCardUiState>,
538→            override val reloadProgressVisibility: Boolean,
539→            override val loadMoreProgressVisibility: Boolean,
540→        ) : DiscoverUiState(contentVisiblity = true, swipeToRefreshEnabled = true)
541→
542→        object LoadingUiState : DiscoverUiState(fullscreenProgressVisibility = true)
543→
544→        sealed class EmptyUiState : DiscoverUiState(fullscreenEmptyVisibility = true) {
545→            abstract val titleResId: Int
546→            abstract val buttonResId: Int
547→            open val subTitleRes: Int? = null
548→            abstract val action: () -> Unit
549→            open val illustrationResId: Int? = null
550→
551→            data class RequestFailedUiState(override val action: () -> Unit) : EmptyUiState() {
552→                override val titleResId = R.string.connection_error
553→                override val subTitleRes = R.string.reader_error_request_failed_title
554→                override val buttonResId = R.string.retry
555→            }
556→
557→            data class ShowNoFollowedTagsUiState(override val action: () -> Unit) : EmptyUiState() {
558→                override val titleResId = R.string.reader_discover_empty_title
559→                override val subTitleRes = R.string.reader_discover_empty_subtitle_subscribe
560→                override val buttonResId = R.string.reader_discover_empty_button_text
561→            }
562→
563→            data class ShowNoPostsUiState(override val action: () -> Unit) : EmptyUiState() {
564→                override val titleResId = R.string.reader_discover_no_posts_title
565→                override val buttonResId = R.string.reader_discover_no_posts_button_tags_text
566→                override val subTitleRes = R.string.reader_discover_no_posts_subscribe_subtitle
567→                override val illustrationResId = R.drawable.illustration_reader_empty
568→            }
569→        }
570→    }
571→}
