 31→class ReaderInterestsViewModel @Inject constructor(
 32→    private val readerTagRepository: ReaderTagRepository,
 33→    private val readerTracker: ReaderTracker
 34→) : ViewModel() {
 35→    private var isStarted = false
 36→    private lateinit var currentLanguage: String
 37→    private var parentViewModel: ReaderViewModel? = null
 38→
 39→    private var entryPoint = EntryPoint.DISCOVER
 40→    private var userTags = ReaderTagList()
 41→
 42→    private val _uiState: MutableLiveData<UiState> = MutableLiveData()
 43→    val uiState: LiveData<UiState> = _uiState
 44→
 45→    private val _snackbarEvents = MediatorLiveData<Event<SnackbarMessageHolder>>()
 46→    val snackbarEvents: LiveData<Event<SnackbarMessageHolder>> = _snackbarEvents
 47→
 48→    private val _closeReaderInterests = MutableLiveData<Event<Unit>>()
 49→    val closeReaderInterests: LiveData<Event<Unit>> = _closeReaderInterests
 50→
 51→    private var userTagsFetchedSuccessfully = false
 52→
 53→    fun start(
 54→        currentLanguage: String,
 55→        parentViewModel: ReaderViewModel?,
 56→        entryPoint: EntryPoint
 57→    ) {
 58→        if (isStarted && this.currentLanguage == currentLanguage) {
 59→            return
 60→        }
 61→        isStarted = true
 62→        this.currentLanguage = currentLanguage
 63→        this.parentViewModel = parentViewModel
 64→        this.entryPoint = entryPoint
 65→        parentViewModel?.dismissQuickStartSnackbarIfNeeded()
 66→        loadUserTags()
 67→    }
 68→
 69→    private fun loadUserTags() {
 70→        updateUiState(InitialLoadingUiState)
 71→        viewModelScope.launch {
 72→            when (val result = readerTagRepository.getUserTags()) {
 73→                is ReaderRepositoryCommunication.SuccessWithData<*> -> {
 74→                    userTagsFetchedSuccessfully = true
 75→                    userTags = result.data as ReaderTagList
 76→                    when (entryPoint) {
 77→                        EntryPoint.DISCOVER -> checkAndLoadInterests(userTags)
 78→                        EntryPoint.SETTINGS -> loadInterests(userTags)
 79→                    }
 80→                }
 81→                is ReaderRepositoryCommunication.Error -> {
 82→                    if (result is ReaderRepositoryCommunication.Error.NetworkUnavailable) {
 83→                        updateUiState(ConnectionErrorUiState)
 84→                    } else if (result is ReaderRepositoryCommunication.Error.RemoteRequestFailure) {
 85→                        updateUiState(RequestFailedErrorUiState)
 86→                    }
 87→                }
 88→                ReaderRepositoryCommunication.Started -> Unit // Do nothing
 89→                ReaderRepositoryCommunication.Success -> Unit // Do nothing
 90→            }
 91→        }
 92→    }
 93→
 94→    private fun checkAndLoadInterests(userTags: ReaderTagList) {
 95→        if (userTags.isEmpty()) {
 96→            loadInterests(userTags)
 97→        } else {
 98→            parentViewModel?.onCloseReaderInterests()
 99→        }
100→    }
101→
102→    private fun loadInterests(userTags: ReaderTagList) {
103→        updateUiState(InitialLoadingUiState)
104→        viewModelScope.launch {
105→            val newUiState: UiState? = when (val result = readerTagRepository.getInterests()) {
106→                is ReaderRepositoryCommunication.SuccessWithData<*> -> {
107→                    readerTracker.track(AnalyticsTracker.Stat.SELECT_INTERESTS_SHOWN)
108→
109→                    val tags = (result.data as ReaderTagList).filter { checkAndExcludeTag(userTags, it) }
110→                    val distinctTags = ReaderTagList().apply { addAll(tags.distinctBy { it.tagSlug }) }
111→                    when (entryPoint) {
112→                        EntryPoint.DISCOVER -> ContentUiState(
113→                            interestsUiState = transformToInterestsUiState(distinctTags),
114→                            interests = distinctTags,
115→                            doneButtonUiState = DoneButtonDisabledUiState(),
116→                            titleVisible = true
117→                        )
118→                        EntryPoint.SETTINGS -> ContentUiState(
119→                            interestsUiState = transformToInterestsUiState(distinctTags),
120→                            interests = distinctTags,
121→                            doneButtonUiState = DoneButtonDisabledUiState(R.string.reader_btn_done),
122→                            titleVisible = false
123→                        )
124→                    }
125→                }
126→                is ReaderRepositoryCommunication.Error.NetworkUnavailable -> {
127→                    ConnectionErrorUiState
128→                }
129→                is ReaderRepositoryCommunication.Error.RemoteRequestFailure -> {
130→                    RequestFailedErrorUiState
131→                }
132→                else -> {
133→                    null
134→                }
135→            }
136→
137→            newUiState?.let {
138→                updateUiState(it)
139→            }
140→        }
141→    }
142→
143→    private fun checkAndExcludeTag(userTags: ReaderTagList, tag: ReaderTag): Boolean {
144→        var contain = false
145→        userTags.forEach { excludedTag ->
146→            if (excludedTag.tagSlug.equals(tag.tagSlug)) {
147→                contain = true
148→                return@forEach
149→            }
150→        }
151→        return !contain
152→    }
153→
154→    fun onInterestAtIndexToggled(index: Int, isChecked: Boolean) {
155→        uiState.value?.let {
156→            val currentUiState = uiState.value as ContentUiState
157→            val updatedInterestsUiState = getUpdatedInterestsUiState(index, isChecked)
158→
159→            updateUiState(
160→                currentUiState.copy(
161→                    interestsUiState = updatedInterestsUiState,
162→                    doneButtonUiState = currentUiState.getDoneButtonState(
163→                        entryPoint = entryPoint,
164→                        isInterestChecked = isChecked
165→                    )
166→                )
167→            )
168→
169→            parentViewModel?.completeQuickStartFollowSiteTaskIfNeeded()
170→        }
171→    }
172→
173→    fun onDoneButtonClick() {
174→        val contentUiState = uiState.value as ContentUiState
175→
176→        updateUiState(
177→            contentUiState.copy(
178→                progressBarVisible = true,
179→                doneButtonUiState = DoneButtonDisabledUiState(R.string.reader_btn_done)
180→            )
181→        )
182→
183→        trackInterests(contentUiState.getSelectedInterests())
184→
185→        viewModelScope.launch {
186→            readerTagRepository.clearTagLastUpdated(ReaderTag.createDiscoverPostCardsTag())
187→            when (val result = readerTagRepository.saveInterests(contentUiState.getSelectedInterests())) {
188→                is ReaderRepositoryCommunication.Success -> {
189→                    when (entryPoint) {
190→                        EntryPoint.DISCOVER -> parentViewModel?.onCloseReaderInterests()
191→                        EntryPoint.SETTINGS -> _closeReaderInterests.value = Event(Unit)
192→                    }
193→                }
194→                is ReaderRepositoryCommunication.Error -> {
195→                    if (result is ReaderRepositoryCommunication.Error.NetworkUnavailable) {
196→                        _snackbarEvents.postValue(
197→                            Event(SnackbarMessageHolder(UiStringRes(R.string.no_network_message)))
198→                        )
199→                    } else if (result is ReaderRepositoryCommunication.Error.RemoteRequestFailure) {
200→                        _snackbarEvents.postValue(
201→                            Event(SnackbarMessageHolder(UiStringRes(R.string.reader_error_request_failed_title)))
202→                        )
203→                    }
204→                    updateUiState(
205→                        contentUiState.copy(
206→                            progressBarVisible = false,
207→                            doneButtonUiState = DoneButtonEnabledUiState(R.string.reader_btn_done)
208→                        )
209→                    )
210→                }
211→                is ReaderRepositoryCommunication.Started -> Unit // Do nothing
212→                is ReaderRepositoryCommunication.SuccessWithData<*> -> Unit // Do nothing
213→            }
214→        }
215→    }
216→
217→    fun onRetryButtonClick() {
218→        if (!userTagsFetchedSuccessfully) {
219→            loadUserTags()
220→        } else {
221→            loadInterests(userTags)
222→        }
223→    }
224→
225→    private fun transformToInterestsUiState(interests: ReaderTagList) =
226→        interests.map { interest ->
227→            TagUiState(interest.tagTitle, interest.tagSlug)
228→        }
229→
230→    private fun getUpdatedInterestsUiState(index: Int, isChecked: Boolean): List<TagUiState> {
231→        val currentUiState = uiState.value as ContentUiState
232→        val newInterestsUiState = currentUiState.interestsUiState.toMutableList()
233→        newInterestsUiState[index] = currentUiState.interestsUiState[index].copy(isChecked = isChecked)
234→        return newInterestsUiState
235→    }
236→
237→    private fun updateUiState(uiState: UiState) {
238→        _uiState.value = uiState
239→    }
240→
241→    private fun trackInterests(tags: List<ReaderTag>) {
242→        tags.forEach {
243→            val source = when (entryPoint) {
244→                EntryPoint.DISCOVER -> ReaderTracker.SOURCE_DISCOVER
245→                EntryPoint.SETTINGS -> ReaderTracker.SOURCE_SETTINGS
246→            }
247→            readerTracker.trackTag(
248→                AnalyticsTracker.Stat.READER_TAG_FOLLOWED,
249→                it.tagSlug,
250→                source
251→            )
252→        }
253→        readerTracker.trackTagQuantity(AnalyticsTracker.Stat.SELECT_INTERESTS_PICKED, tags.size)
254→    }
255→
256→    fun onBackButtonClick() {
257→        when (entryPoint) {
258→            EntryPoint.DISCOVER -> parentViewModel?.onCloseReaderInterests()
259→            EntryPoint.SETTINGS -> _closeReaderInterests.value = Event(Unit)
260→        }
261→    }
262→
263→    sealed class UiState(
264→        open val doneButtonUiState: DoneButtonUiState = DoneButtonHiddenUiState,
265→        open val progressBarVisible: Boolean = false,
266→        open val titleVisible: Boolean = false,
267→        val errorLayoutVisible: Boolean = false
268→    ) {
269→        object InitialLoadingUiState : UiState(
270→            progressBarVisible = true
271→        )
272→
273→        data class ContentUiState(
274→            val interestsUiState: List<TagUiState>,
275→            val interests: ReaderTagList,
276→            override val progressBarVisible: Boolean = false,
277→            override val doneButtonUiState: DoneButtonUiState,
278→            override val titleVisible: Boolean
279→        ) : UiState(
280→            progressBarVisible = false,
281→            titleVisible = titleVisible,
282→            errorLayoutVisible = false
283→        )
284→
285→        sealed class ErrorUiState constructor(
286→            val titleRes: Int
287→        ) : UiState(
288→            progressBarVisible = false,
289→            errorLayoutVisible = true
290→        ) {
291→            object ConnectionErrorUiState : ErrorUiState(R.string.no_network_message)
292→
293→            object RequestFailedErrorUiState : ErrorUiState(R.string.reader_error_request_failed_title)
294→        }
295→
296→        private fun getCheckedInterestsUiState(): List<TagUiState> {
297→            return if (this is ContentUiState) {
298→                interestsUiState.filter { it.isChecked }
299→            } else {
300→                emptyList()
301→            }
302→        }
303→
304→        fun getSelectedInterests(): List<ReaderTag> {
305→            return if (this is ContentUiState) {
306→                interests.filter {
307→                    getCheckedInterestsUiState().map { checkedInterestUiState ->
308→                        checkedInterestUiState.slug
309→                    }.contains(it.tagSlug)
310→                }
311→            } else {
312→                emptyList()
313→            }
314→        }
315→
316→        fun getDoneButtonState(
317→            entryPoint: EntryPoint,
318→            isInterestChecked: Boolean = false
319→        ): DoneButtonUiState {
320→            return if (this is ContentUiState) {
321→                val disableDoneButton = interests.isEmpty() ||
322→                        (getCheckedInterestsUiState().size == 1 && !isInterestChecked)
323→                if (disableDoneButton) {
324→                    when (entryPoint) {
325→                        EntryPoint.DISCOVER -> DoneButtonDisabledUiState()
326→                        EntryPoint.SETTINGS -> DoneButtonDisabledUiState(R.string.reader_btn_done)
327→                    }
328→                } else {
329→                    DoneButtonEnabledUiState()
330→                }
331→            } else {
332→                DoneButtonHiddenUiState
333→            }
334→        }
335→    }
336→
337→    sealed class DoneButtonUiState(
338→        @StringRes open val titleRes: Int = R.string.reader_btn_done,
339→        val enabled: Boolean = false,
340→        val visible: Boolean = true
341→    ) {
342→        data class DoneButtonEnabledUiState(
343→            @StringRes override val titleRes: Int = R.string.reader_btn_done
344→        ) : DoneButtonUiState(
345→            enabled = true
346→        )
347→
348→        data class DoneButtonDisabledUiState(
349→            @StringRes override val titleRes: Int = R.string.reader_btn_select_few_interests
350→        ) : DoneButtonUiState(
351→            enabled = false
352→        )
353→
354→        object DoneButtonHiddenUiState : DoneButtonUiState(
355→            visible = false
356→        )
357→    }
358→}
