 3→public enum ReaderTagType {
 4→    FOLLOWED,
 5→    DEFAULT,
 6→    BOOKMARKED,
 7→    CUSTOM_LIST,
 8→    SEARCH,
 9→    INTERESTS,
10→    DISCOVER_POST_CARDS;
11→
12→    private static final int INT_DEFAULT = 0;
13→    private static final int INT_FOLLOWED = 1;
14→    // 2 - don't use it. It was used for recommended tags which are not used anymore
15→    private static final int INT_CUSTOM_LIST = 3;
16→    private static final int INT_SEARCH = 4;
17→    private static final int INT_BOOKMARKED = 5;
18→    private static final int INT_INTERESTS = 6;
19→    private static final int INT_DISCOVER_POST_CARDS = 7;
20→
21→
22→    public static ReaderTagType fromInt(int value) {
23→        switch (value) {
24→            case INT_FOLLOWED:
25→                return FOLLOWED;
26→            case INT_CUSTOM_LIST:
27→                return CUSTOM_LIST;
28→            case INT_SEARCH:
29→                return SEARCH;
30→            case INT_BOOKMARKED:
31→                return BOOKMARKED;
32→            case INT_INTERESTS:
33→                return INTERESTS;
34→            case INT_DISCOVER_POST_CARDS:
35→                return DISCOVER_POST_CARDS;
36→            default:
37→                return DEFAULT;
38→        }
39→    }
40→
41→    public int toInt() {
42→        switch (this) {
43→            case FOLLOWED:
44→                return INT_FOLLOWED;
45→            case CUSTOM_LIST:
46→                return INT_CUSTOM_LIST;
47→            case SEARCH:
48→                return INT_SEARCH;
49→            case BOOKMARKED:
50→                return INT_BOOKMARKED;
51→            case INTERESTS:
52→                return INT_INTERESTS;
53→            case DISCOVER_POST_CARDS:
54→                return INT_DISCOVER_POST_CARDS;
55→            case DEFAULT:
56→            default:
57→                return INT_DEFAULT;
58→        }
59→    }
60→}
