158→
159→            updateUiState(
160→                currentUiState.copy(
161→                    interestsUiState = updatedInterestsUiState,
162→                    doneButtonUiState = currentUiState.getDoneButtonState(
163→                        entryPoint = entryPoint,
164→                        isInterestChecked = isChecked
