187→            when (val result = readerTagRepository.saveInterests(contentUiState.getSelectedInterests())) {
188→                is ReaderRepositoryCommunication.Success -> {
189→                    when (entryPoint) {
190→                        EntryPoint.DISCOVER -> parentViewModel?.onCloseReaderInterests()
191→                        EntryPoint.SETTINGS -> _closeReaderInterests.value = Event(Unit)
192→                    }
193→                }
194→                is ReaderRepositoryCommunication.Error -> {
195→                    if (result is ReaderRepositoryCommunication.Error.NetworkUnavailable) {
196→                        _snackbarEvents.postValue(
197→                            Event(SnackbarMessageHolder(UiStringRes(R.string.no_network_message)))
198→                        )
199→                    } else if (result is ReaderRepositoryCommunication.Error.RemoteRequestFailure) {
200→                        _snackbarEvents.postValue(
201→                            Event(SnackbarMessageHolder(UiStringRes(R.string.reader_error_request_failed_title)))
202→                        )
203→                    }
204→                    updateUiState(
205→                        contentUiState.copy(
206→                            progressBarVisible = false,
207→                            doneButtonUiState = DoneButtonEnabledUiState(R.string.reader_btn_done)
208→                        )
209→                    )
210→                }
211→                is ReaderRepositoryCommunication.Started -> Unit // Do nothing
212→                is ReaderRepositoryCommunication.SuccessWithData<*> -> Unit // Do nothing
213→            }
214→        }
215→    }
